// Define a function to validate Docker service port mappings.
function validatePortMappings(serviceName, portMappings) {
  let usedPorts = {};
  for (let mapping of portMappings) {
    if (mapping.port !== mapping.containerPort && mapping.containerPort < 1 || mapping.containerPort > 65535) {
      return false;
    }
    if (usedPorts[serviceName] && usedPorts[serviceName].includes(mapping.containerPort)) {
      return false;
    }
    usedPorts[serviceName] = usedPorts[serviceName] || [];
    usedPorts[serviceName].push(mapping.containerPort);
  }
  return true;
}
